import React from 'react';

const RoomCard = React.memo(function RoomCard({ room, onSelect, isBooked }) {
  return (
    <div style={styles.card} onClick={() => onSelect(room)}>
      {isBooked && <div style={styles.bookedBadge}>BOOKED</div>}
      <div style={styles.img}>{room.image}</div>
      <div style={styles.body}>
        <div style={styles.type}>{room.type}</div>
        <div style={styles.name}>{room.name}</div>
        <div style={styles.amenities}>
          {room.amenities.map((a) => (
            <span key={a} style={styles.tag}>
              {a}
            </span>
          ))}
        </div>
        <div style={styles.footer}>
          <div>
            <span style={styles.price}>₹{room.price.toLocaleString()}</span>
            <span style={styles.per}> /night</span>
          </div>
          <span style={styles.capacity}>
            👤 {room.capacity} {room.capacity > 1 ? 'guests' : 'guest'}
          </span>
        </div>
      </div>
    </div>
  );
});

const styles = {
  card: {
    background: 'var(--surface)',
    border: '1px solid var(--border)',
    borderRadius: 8,
    overflow: 'hidden',
    cursor: 'pointer',
    transition: 'all 0.25s',
    display: 'flex',
    flexDirection: 'column',
    position: 'relative',
  },
  bookedBadge: {
    position: 'absolute',
    top: 12,
    right: 12,
    background: 'var(--gold)',
    color: 'var(--ink)',
    fontSize: 10,
    fontWeight: 700,
    padding: '3px 8px',
    borderRadius: 20,
    zIndex: 2,
    letterSpacing: '0.1em',
  },
  img: {
    height: 140,
    background: 'var(--warm)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: 64,
    borderBottom: '1px solid var(--border)',
  },
  body: { padding: 24, flex: 1, display: 'flex', flexDirection: 'column' },
  type: {
    fontSize: 10,
    letterSpacing: '0.2em',
    textTransform: 'uppercase',
    color: 'var(--gold)',
    fontWeight: 500,
    marginBottom: 6,
  },
  name: {
    fontFamily: "'Cormorant Garamond', serif",
    fontSize: 22,
    fontWeight: 400,
    marginBottom: 12,
  },
  amenities: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: 6,
    marginBottom: 20,
    flex: 1,
  },
  tag: {
    fontSize: 11,
    padding: '3px 8px',
    background: 'var(--warm)',
    border: '1px solid var(--border)',
    borderRadius: 20,
    color: 'var(--muted)',
  },
  footer: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    paddingTop: 16,
    borderTop: '1px solid var(--border)',
  },
  price: {
    fontFamily: "'Cormorant Garamond', serif",
    fontSize: 28,
    fontWeight: 600,
  },
  per: { fontSize: 12, color: 'var(--muted)' },
  capacity: { fontSize: 12, color: 'var(--muted)' },
};

export default RoomCard;
